const input = $json || {};
if (!input.agent_role) throw new Error('agent_role is required');
if (input.decision === undefined || input.decision === null) throw new Error('decision is required');

const parseObject = (value, fallback = {}) => {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'object') return value;
  if (typeof value !== 'string') return fallback;
  try { return JSON.parse(value); } catch (_) { return fallback; }
};

const parseBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') return ['true', '1', 'yes', 'si', 'sí'].includes(value.trim().toLowerCase());
  return false;
};

const firstNonEmpty = (...values) => values.find((value) =>
  value !== undefined && value !== null && String(value).trim() !== ''
);

const normalizeRisk = (value) => {
  const risk = String(value || 'low').trim().toLowerCase();
  return ['low', 'medium', 'high', 'critical'].includes(risk) ? risk : 'low';
};

const normalizeDeadline = (value) => {
  const raw = firstNonEmpty(value);
  if (!raw) return null;
  const date = new Date(raw);
  return Number.isNaN(date.getTime()) ? null : date.toISOString();
};

const decisionObj = typeof input.decision === 'string'
  ? parseObject(input.decision, { raw: input.decision })
  : parseObject(input.decision, {});

const contextUsed = parseObject(input.context_used, {});
const evidence = parseObject(input.evidence, {});
const requiresApproval = parseBool(input.requires_human_approval);
const confidenceRaw = Number.parseFloat(input.confidence);
const confidenceNormalized = Number.isFinite(confidenceRaw)
  ? Math.max(0, Math.min(1, confidenceRaw > 1 ? confidenceRaw / 100 : confidenceRaw))
  : 1.0;

const pmImpact = firstNonEmpty(
  input.pm_impact,
  input.impact,
  decisionObj.impact,
  decisionObj.pm_impact,
  decisionObj.summary,
  input.input_summary,
  input.recommendation
);
const pmNextAction = firstNonEmpty(
  input.pm_next_action,
  input.next_action,
  decisionObj.next_action,
  decisionObj.pm_next_action,
  decisionObj.suggested_action,
  decisionObj.suggested_comment,
  input.recommendation
);
const pmOwner = firstNonEmpty(
  input.pm_owner,
  input.owner,
  decisionObj.owner,
  decisionObj.pm_owner,
  contextUsed.owner,
  contextUsed.actor,
  input.actor,
  'Tech Lead'
);
const pmDeadline = normalizeDeadline(firstNonEmpty(
  input.pm_deadline,
  input.deadline,
  decisionObj.deadline,
  decisionObj.pm_deadline
));
const pmRiskReason = firstNonEmpty(
  input.pm_risk_reason,
  input.risk_reason,
  decisionObj.risk_reason,
  decisionObj.pm_risk_reason,
  decisionObj.analysis,
  input.recommendation
);

return [{
  json: {
    ...input,
    correlation_id: input.correlation_id || `ai-${Date.now()}`,
    decision_type: input.decision_type || 'general',
    risk_level: normalizeRisk(input.risk_level || decisionObj.risk_level),
    confidence: confidenceNormalized,
    requires_human_approval: requiresApproval,
    status: input.status || (requiresApproval ? 'pending_approval' : 'approved'),
    decision: decisionObj,
    context_used: contextUsed,
    evidence,
    pm_impact: pmImpact || null,
    pm_next_action: pmNextAction || null,
    pm_owner: pmOwner || null,
    pm_deadline: pmDeadline,
    pm_risk_reason: pmRiskReason || null
  }
}];

const decisionId = $json.decision_id;
const role = $('Validate & Format').item.json.agent_role;
const recommendation = $('Validate & Format').item.json.recommendation;
const risk = $('Validate & Format').item.json.risk_level;

const content = `**Aprobación de IA Requerida**\nEl agente **${role}** ha propuesto una acción de riesgo **${risk}**.\n\n**Recomendación:** ${recommendation}\n\nID: \`${decisionId}\`\nHub: /webhook/pm-approvals`;

return [{
  json: {
    outbox_target: 'discord',
    outbox_action: 'notify',
    outbox_payload: { content },
    event_id: 'ai-decision:' + decisionId,
    idempotency_key: 'ai-decision:' + decisionId,
    correlation_id: $('Validate & Format').item.json.correlation_id
  }
}];

